#[repr(i32)]
#[doc = "\n \\enum PaddingMode\n\n \\brief Enumerates the modes of padding to perform in convolution, deconvolution and pooling layer,\n padding mode takes precedence if setPaddingMode() and setPrePadding() are also used.\n\n There are two padding styles, EXPLICIT and SAME with each style having two variants.\n The EXPLICIT style determine if the final sampling location is used or not.\n The SAME style determine if the asymmetry in the padding is on the pre or post padding.\n\n \\code\n Shorthand:\n     I = dimensions of input image.\n     B = prePadding, before the image data.\n     A = postPadding, after the image data.\n     P = delta between input and output\n     S = stride\n     F = filter\n     O = output\n     D = dilation\n     M = I + B + A ; The image data plus any padding\n     DK = 1 + D * (F - 1)\n \\endcode\n\n Formulas for Convolution:\n     - EXPLICIT_ROUND_DOWN:\n \\code\n         O = floor((M - DK) / S) + 1\n \\endcode\n     - EXPLICIT_ROUND_UP:\n \\code\n         O = ceil((M - DK) / S) + 1\n \\endcode\n     - SAME_UPPER:\n \\code\n         O = ceil(I / S)\n         P = floor((I - 1) / S) * S + DK - I;\n         B = floor(P / 2)\n         A = P - B\n \\endcode\n     - SAME_LOWER:\n \\code\n         O = ceil(I / S)\n         P = floor((I - 1) / S) * S + DK - I;\n         A = floor(P / 2)\n         B = P - A\n \\endcode\n\n Formulas for Deconvolution:\n     - EXPLICIT_ROUND_DOWN:\n     - EXPLICIT_ROUND_UP:\n \\code\n         O = (I - 1) * S + DK - (B + A)\n \\endcode\n     - SAME_UPPER:\n \\code\n         O = min(I * S, (I - 1) * S + DK)\n         P = max(DK - S, 0)\n         B = floor(P / 2)\n         A = P - B\n \\endcode\n     - SAME_LOWER:\n \\code\n         O = min(I * S, (I - 1) * S + DK)\n         P = max(DK - S, 0)\n         A = floor(P / 2)\n         B = P - A\n \\endcode\n\n Formulas for Pooling:\n     - EXPLICIT_ROUND_DOWN:\n \\code\n         O = floor((M - F) / S) + 1\n \\endcode\n     - EXPLICIT_ROUND_UP:\n \\code\n         O = ceil((M - F) / S) + 1\n \\endcode\n     - SAME_UPPER:\n \\code\n         O = ceil(I / S)\n         P = floor((I - 1) / S) * S + F - I;\n         B = floor(P / 2)\n         A = P - B\n \\endcode\n     - SAME_LOWER:\n \\code\n         O = ceil(I / S)\n         P = floor((I - 1) / S) * S + F - I;\n         A = floor(P / 2)\n         B = P - A\n \\endcode\n\n Pooling Example 1:\n \\code\n     Given I = {6, 6}, B = {3, 3}, A = {2, 2}, S = {2, 2}, F = {3, 3}. What is O?\n     (B, A can be calculated for SAME_UPPER and SAME_LOWER mode)\n \\endcode\n\n - EXPLICIT_ROUND_DOWN:\n \\code\n     Computation:\n         M = {6, 6} + {3, 3} + {2, 2} ==> {11, 11}\n         O ==> floor((M - F) / S) + 1\n           ==> floor(({11, 11} - {3, 3}) / {2, 2}) + {1, 1}\n           ==> floor({8, 8} / {2, 2}) + {1, 1}\n           ==> {5, 5}\n \\endcode\n - EXPLICIT_ROUND_UP:\n \\code\n     Computation:\n         M = {6, 6} + {3, 3} + {2, 2} ==> {11, 11}\n         O ==> ceil((M - F) / S) + 1\n           ==> ceil(({11, 11} - {3, 3}) / {2, 2}) + {1, 1}\n           ==> ceil({8, 8} / {2, 2}) + {1, 1}\n           ==> {5, 5}\n \\endcode\n     The sample points are {0, 2, 4, 6, 8} in each dimension.\n\n - SAME_UPPER:\n \\code\n     Computation:\n         I = {6, 6}\n         S = {2, 2}\n         O = ceil(I / S) = {3, 3}\n         P = floor((I - 1) / S) * S + F - I\n             ==> floor(({6, 6} - {1, 1}) / {2, 2}) * {2, 2} + {3, 3} - {6, 6}\n             ==> {4, 4} + {3, 3} - {6, 6}\n             ==> {1, 1}\n         B = floor({1, 1} / {2, 2})\n             ==> {0, 0}\n         A = {1, 1} - {0, 0}\n             ==> {1, 1}\n \\endcode\n - SAME_LOWER:\n \\code\n     Computation:\n         I = {6, 6}\n         S = {2, 2}\n         O = ceil(I / S) = {3, 3}\n         P = floor((I - 1) / S) * S + F - I\n           ==> {1, 1}\n         A = floor({1, 1} / {2, 2})\n           ==> {0, 0}\n         B = {1, 1} - {0, 0}\n           ==> {1, 1}\n \\endcode\n     The sample pointers are {0, 2, 4} in each dimension.\n     SAMPLE_UPPER has {O0, O1, O2, pad} in output in each dimension.\n     SAMPLE_LOWER has {pad, O0, O1, O2} in output in each dimension.\n\n Pooling Example 2:\n \\code\n     Given I = {6, 6}, B = {3, 3}, A = {3, 3}, S = {2, 2}, F = {3, 3}. What is O?\n \\endcode\n"]
#[derive(Debug, Copy, Clone, Hash, PartialOrd, Ord, PartialEq, Eq)]
pub enum PaddingMode {
    #[doc = "< Use explicit padding, rounding output size down."]
    kEXPLICIT_ROUND_DOWN = 0,
    #[doc = "< Use explicit padding, rounding output size up."]
    kEXPLICIT_ROUND_UP = 1,
    #[doc = "< Use SAME padding, with prePadding <= postPadding."]
    kSAME_UPPER = 2,
    #[doc = "< Use SAME padding, with prePadding >= postPadding."]
    kSAME_LOWER = 3,
}
